SELECT [DDT_Picking Header].[Salesperson Code], Salesperson_Purchaser.Name, [DDT_Picking Header].[Sell-to Customer No_], [DDT_Picking Header].[Bill-to Name], [DDT_Picking Line].[Document No_], [DDT_Picking Header].[Ship Provider Order ID], [DDT_Picking Line].[Line No_], [DDT_Picking Line].No_ AS Article, [DDT_Picking Line].[Constant Variable Code] AS ColorCode, [DDT_Picking Line].[Assortment Code], [DDT_Picking Header].[Shortcut Dimension 2 Code] AS Marchio, [DDT_Picking Header].[SELLING SEASON CODE] AS StagioneVendita, Val([ddt_picking line.quantity]) AS qty, 1 AS PrelievoRegistrato, [Registered Whse_ Activity Line].No_ AS NumeroPrelievo, [Registered Whse_ Activity Line].[Whse_ Phase Code] AS FasePrelievo, [Registered Whse_ Activity Line].[Bin Code], [Unique Identifier Pst_ Docnts].Code, [Warehouse Shipment Line].No_ AS SpedWarehouseNo, [Warehouse Shipment Header].[Special Requests], [Warehouse Shipment Header].[Warehouse Speciality Code], [Warehouse Shipment Header].[Warehouse Note], [Warehouse Shipment Header].[Posting Date] AS SpedWarehouseData
FROM ([Unique Identifier Pst_ Docnts] RIGHT JOIN ([Registered Whse_ Activity Line] RIGHT JOIN (([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) LEFT JOIN Salesperson_Purchaser ON [DDT_Picking Header].[Salesperson Code] = Salesperson_Purchaser.Code) ON ([Registered Whse_ Activity Line].[Link To Source Line No_] = [DDT_Picking Line].[Line No_]) AND ([Registered Whse_ Activity Line].[Link To Source No_] = [DDT_Picking Line].[Document No_])) ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Registered Whse_ Activity Line].[Line No_]) AND ([Unique Identifier Pst_ Docnts].No_ = [Registered Whse_ Activity Line].No_)) INNER JOIN ([Warehouse Shipment Line] INNER JOIN [Warehouse Shipment Header] ON [Warehouse Shipment Line].No_ = [Warehouse Shipment Header].No_) ON ([Warehouse Shipment Line].[Source Line No_] = [DDT_Picking Line].[Line No_]) AND ([DDT_Picking Line].[Document No_] = [Warehouse Shipment Line].[Source No_])
WHERE ((([DDT_Picking Header].Status)=1) AND (([DDT_Picking Line].Type)=20) AND (([DDT_Picking Header].[Document Type])=0))
ORDER BY [DDT_Picking Line].[Document No_], [DDT_Picking Line].[Line No_], [Registered Whse_ Activity Line].No_, [Registered Whse_ Activity Line].[Whse_ Phase Code], [Unique Identifier Pst_ Docnts].Code;

